    if(pricebook.size() == 1){
        List<Opportunity> opps = [SELECT Id, SBQQ__QuotePricebookId__c FROM Opportunity WHERE SBQQ__QuotePricebookId__c = NULL AND Id IN :trigger.newMap.keySet()];
